func solve(nums []int64, queries [][]int64) int64 {
    MOD := int64(1000000007)
    n := len(nums)
    product := make([]int64, n)
    for i := range product {
        product[i] = 1
    }
    for _, query := range queries {
        li := query[0]
        ri := query[1]
        ki := query[2]
        vi := query[3]
        idx := li
        for idx <= ri {
            product[idx] = (product[idx] * vi) % MOD
            idx += ki
        }
    }
    var xorResult int64
    for i := 0; i < n; i++ {
        xorResult ^= (nums[i] * product[i]) % MOD
    }
    return xorResult
}
